query:
-- Clean up carModels with invalid userId or makerId
DELETE FROM carModels WHERE userId IS NOT NULL AND userId NOT IN (SELECT id FROM users);
DELETE FROM carModels WHERE makerId NOT IN (SELECT id FROM carMakers);

-- Clean up carMakers with invalid userId
DELETE FROM carMakers WHERE userId IS NOT NULL AND userId NOT IN (SELECT id FROM users);

-- Clean up other tables
DELETE FROM invoiceLineItems WHERE invoiceId NOT IN (SELECT id FROM invoices);
DELETE FROM vehicleImages WHERE vehicleId NOT IN (SELECT id FROM vehicles);
DELETE FROM insurancePolicies WHERE vehicleId NOT IN (SELECT id FROM vehicles);

-- Verify all orphaned records are cleaned
SELECT 'Cleanup complete' as status;
SELECT COUNT(*) as orphaned_carmodels_user FROM carModels WHERE userId IS NOT NULL AND userId NOT IN (SELECT id FROM users);
SELECT COUNT(*) as orphaned_carmodels_maker FROM carModels WHERE makerId NOT IN (SELECT id FROM carMakers);

